type ValidationStatus = "green" | "yellow" | "red" | "gray";
type ValidationSeverity = "info" | "minor" | "critical";
type ValidationCategory =
  | "fixedAssets"
  | "AR"
  | "AP"
  | "inventory"
  | "debt"
  | "payroll"
  | "flux"
  | "GL"
  | "netIncome"
  | "periods";

type ValidationCheck = {
  id: string;
  category: ValidationCategory;
  label: string;
  expectedBalance: number | null;
  actualBalance: number | null;
  variance: number | null;
  tolerance: number | null;
  severity: ValidationSeverity;
  status: ValidationStatus;
  message: string;
  confidenceImpact: number;
};

type ValidationResults = {
  fixedAssets: ValidationCheck[];
  AR: ValidationCheck[];
  AP: ValidationCheck[];
  inventory: ValidationCheck[];
  debt: ValidationCheck[];
  payroll: ValidationCheck[];
  flux: ValidationCheck[];
  GL: ValidationCheck[];
  netIncome: ValidationCheck[];
  periods: ValidationCheck[];
  checks: ValidationCheck[];
  financialConfidenceScore: number;
  fluxConfidenceScore: number;
  KPIConfidenceScore: number;
  PDFConfidenceScore: number;
  AICommentaryConfidenceScore: number;
  hasCriticalFailures: boolean;
  status: ValidationStatus;
  summary: string;
};
type PackageQaFinding = {
  id: string;
  severity: ValidationSeverity;
  category:
    | "calculation"
    | "commentary"
    | "relationship"
    | "possible-accrual"
    | "executive-summary"
    | "ar-reserve"
    | "reserve-lifecycle"
    | "ap-cutoff"
    | "revenue-recognition"
    | "workforce"
    | "treasury"
    | "fixed-asset-integrity"
    | "manufacturing-inventory"
    | "close-management";
  message: string;
  internalOnly: true;
};

type ValidationToleranceConfig = {
  financialStatementTotals: number;
  glAggregation: number;
  inventoryQuantities: number;
  payrollPercent: number;
  percentageThreshold: number;
};

type FluxDebugInfo = {
  currentRowsParsed: number;
  priorRowsParsed: number;
  accountsGrouped: number;
  variancesCalculated: number;
  variancesPassingThreshold: number;
};

type FluxSettings = {
  dollarThreshold: number;
  percentThreshold: number;
  logic: ThresholdLogic;
  includeZeroActivity: boolean;
};

