function isProfessionalOrHigher(tier: PackageTier) {
  return tier === "professional" || tier === "virtualCfo";
}

function isVirtualCfo(tier: PackageTier) {
  return tier === "virtualCfo";
}

function getDefaultRatiosForPackage(tier: PackageTier): RatioId[] {
  if (tier === "essential") {
    return [
      "Net Margin",
      "Gross Margin",
      "Operating Margin",
      "EBITDA Margin",
      "Expense Ratio",
      "Current Ratio",
      "Quick Ratio",
      "Cash to Assets",
      "Accounts Receivable to Assets",
      "AP to Revenue",
      "Working Capital Estimate",
      "DSO",
    ];
  }
  if (tier === "professional") {
    return [
      ...getDefaultRatiosForPackage("essential"),
      "Inventory to Total Assets",
      "Inventory Turnover",
      "AR Turnover",
      "AP Turnover",
      "Cash Conversion Cycle",
    ];
  }
  return [
    ...getDefaultRatiosForPackage("professional"),
    "Payroll Cost as % of Revenue",
    "Gross Wages as % of Revenue",
    "Payroll Taxes as % of Gross Wages",
    "Payroll Cost per FTE",
    "Revenue per FTE",
    "Gross Profit per FTE",
    "Debt to Equity",
    "Debt to Assets",
  ];
}

function getClientSettingsKey(clientName: string) {
  return `advisacor_client_package_settings_${clientName.trim().toLowerCase().replace(/\s+/g, "_")}`;
}

function filterSelectedFluxRows(rows: FluxRow[], includeHighOnly: boolean, includeModerate: boolean, maxRows: number) {
  return rows
    .filter((row) => {
      if (includeHighOnly) return row.severity === "High";
      if (!includeModerate) return row.severity !== "Moderate";
      return true;
    })
    .slice(0, Math.max(maxRows || 0, 1));
}

function getFluxRowKey(row: FluxRow, basisLabel: string = row.basis) {
  return `${basisLabel}:${row.accountNumber || "no-account"}:${row.accountName}`.toLowerCase();
}

function isReportRequiredForPackage(reportId: string, packageTier: PackageTier) {
  return packageRequirements[packageTier].some((requirement) => requirement.reportIds.includes(reportId));
}

function isReportRequiredForOpenRequirement(
  reportId: string,
  packageTier: PackageTier,
  reports: UploadReport[],
) {
  return packageRequirements[packageTier].some((requirement) => {
    if (!requirement.reportIds.includes(reportId)) return false;

    return !requirement.reportIds.some((requirementReportId) => {
      const matchingReport = reports.find((report) => report.id === requirementReportId);
      return Boolean(matchingReport?.data || matchingReport?.omitted);
    });
  });
}

function getPackageRequirementStatuses(
  packageTier: PackageTier,
  reports: UploadReport[],
): PackageRequirementStatus[] {
  return packageRequirements[packageTier].map((requirement) => {
    const matchingReports = requirement.reportIds
      .map((reportId) => reports.find((report) => report.id === reportId))
      .filter(Boolean) as UploadReport[];
    const uploaded = matchingReports.some((report) => Boolean(report.data));
    const omitted = matchingReports.some((report) => report.omitted);

    return {
      ...requirement,
      uploaded,
      omitted,
      resolved: uploaded || omitted,
    };
  });
}

function getPackageRequiredReportIds(packageTier: PackageTier) {
  return Array.from(new Set(packageRequirements[packageTier].flatMap((requirement) => requirement.reportIds)));
}

function normalizeFileNameForMatch(fileName: string) {
  return fileName
    .replace(/\.[^.]+$/, "")
    .replace(/([a-z0-9])([A-Z])/g, "$1 $2")
    .replace(/([A-Z]+)([A-Z][a-z])/g, "$1 $2")
    .toLowerCase()
    .replace(/[_-]+/g, " ")
    .replace(/\bapaging\b/g, "ap aging")
    .replace(/\baraging\b/g, "ar aging")
    .replace(/\bgl\b/g, "general ledger")
    .replace(/\s+/g, " ")
    .trim();
}

function compactFileNameForMatch(fileName: string) {
  return normalizeFileNameForMatch(fileName).replace(/[^a-z0-9]/g, "");
}

function isSupportedImportFile(file: File) {
  return /\.(csv|xls|xlsx)$/i.test(file.name);
}

function getReportFileMatchScore(reportId: string, fileName: string) {
  const normalizedFileName = normalizeFileNameForMatch(fileName);
  const compactFileName = compactFileNameForMatch(fileName);
  const keywords = REPORT_FILENAME_KEYWORDS[reportId] || [];

  const keywordScore = keywords.reduce((score, keyword) => {
    const normalizedKeyword = normalizeFileNameForMatch(keyword);
    const compactKeyword = compactFileNameForMatch(keyword);
    const spacedMatch = normalizedFileName.includes(normalizedKeyword);
    const compactMatch = compactKeyword.length > 2 && compactFileName.includes(compactKeyword);
    return spacedMatch || compactMatch ? score + compactKeyword.length : score;
  }, 0);

  const isPayrollSummaryFile =
    compactFileName.includes("payrollsummarybydepartment") ||
    (compactFileName.includes("payrollsummary") && compactFileName.includes("department"));
  const isPayrollDetailFile =
    compactFileName.includes("payrollgldetail") ||
    (compactFileName.includes("payrolldetail") && !compactFileName.includes("summary"));
  const isCurrentPeriod =
    compactFileName.includes("currentmonth") ||
    compactFileName.includes("current") ||
    compactFileName.includes("dec2025");
  const isPriorPeriod =
    compactFileName.includes("priormonth") ||
    compactFileName.includes("prior") ||
    compactFileName.includes("previous") ||
    compactFileName.includes("nov2025");
  const isInventoryValuationFile =
    compactFileName.includes("inventoryvaluation") ||
    (compactFileName.includes("inventory") && compactFileName.includes("valuation"));
  const isPriorInventory =
    reportId === "prior-inventory" &&
    isInventoryValuationFile &&
    (compactFileName.includes("priorperiod") || compactFileName.includes("prior") || compactFileName.includes("previous"));

  if (reportId === "inventory" && isInventoryValuationFile && (compactFileName.includes("prior") || compactFileName.includes("previous"))) {
    return 0;
  }

  if (isPriorInventory) {
    return keywordScore + 100;
  }
  const isCurrentPayrollSummary =
    reportId === "current-payroll" &&
    isPayrollSummaryFile &&
    isCurrentPeriod;
  const isPriorPayrollSummary =
    reportId === "prior-payroll" &&
    isPayrollSummaryFile &&
    isPriorPeriod;
  const isCurrentPayrollDetail =
    reportId === "current-payroll-detail" &&
    isPayrollDetailFile &&
    isCurrentPeriod;
  const isPriorPayrollDetail =
    reportId === "prior-payroll-detail" &&
    isPayrollDetailFile &&
    isPriorPeriod;

  if (isCurrentPayrollSummary || isPriorPayrollSummary || isCurrentPayrollDetail || isPriorPayrollDetail) {
    return keywordScore + 80;
  }

  return keywordScore;
}

function getBestReportMatch(file: File, reports: UploadReport[]) {
  const scoredReports = reports
    .map((report) => ({ report, score: getReportFileMatchScore(report.id, file.name) }))
    .filter((item) => item.score > 0)
    .sort((a, b) => b.score - a.score);

  return scoredReports[0]?.report || null;
}

/**
 * Whole-dollar accounting-parens currency formatter used throughout the
 * board-package/financial-package export path.
 *
 * Legacy behavior (MC-2d.3a and earlier):
 *   formatCurrency(1234)  === "$1,234"
 *   formatCurrency(-1234) === "($1,234)"
 *   formatCurrency(null)  === ""
 *
 * MC-2d.3a (this PR) makes the currency code an optional parameter. All
 * existing call sites (~425 in this file) omit the argument and thus
 * continue to get byte-identical `"$..."` output. MC-2d.3b will migrate
 * those call sites to pass an explicit currency threaded from the QBO
 * `company_profile.home_currency` field.
 *
 * When a non-USD currency is supplied, output uses the currency's ISO
 * symbol from `@/lib/format/money`, preserves whole-dollar rounding, and
 * wraps negatives in accounting parens (e.g. `formatCurrency(-1234, "CAD")
 * === "(CA$1,234)"`).
 */
function formatCurrency(
  value: number | null | undefined,
  currency: string | null | undefined = DEFAULT_FALLBACK_CURRENCY,
) {
  if (value === null || value === undefined) return "";

  const amount = Math.round(value);
  const resolvedCurrency =
    typeof currency === "string" && isValidCurrencyCode(currency)
      ? currency
      : DEFAULT_FALLBACK_CURRENCY;

  // Use the shared formatter for the absolute value, then wrap negatives in
  // accounting parens to preserve the board-package CFO convention.
  const formatted = formatMoneyShared(Math.abs(amount), resolvedCurrency, {
    minimumFractionDigits: 0,
    maximumFractionDigits: 0,
    signDisplay: "never",
  });

  return amount < 0 ? `(${formatted})` : formatted;
}

/**
 * Nullish-coalescing wrapper around `formatCurrency` used across the board-
 * package narrative builders. Renamed from `formatMoney` in MC-2d.3a to end
 * the shadow of `formatMoney` from `@/lib/format/money`.
 *
 * Legacy behavior (unchanged):
 *   formatMoneyLegacy(1234)  === "$1,234"
 *   formatMoneyLegacy(-1234) === "($1,234)"
 *   formatMoneyLegacy(null)  === "$0"   // note: legacy coalesces null → 0
 *
 * MC-2d.3b will migrate call sites one-by-one; MC-2d.3c will delete this
 * function entirely once all 178 call sites route through the shared
 * `formatMoney` from `@/lib/format/money`.
 */
function formatMoneyLegacy(
  value: number | null | undefined,
  currency: string | null | undefined = DEFAULT_FALLBACK_CURRENCY,
) {
  return formatCurrency(value ?? 0, currency);
}

function formatPeriodEnding(value: string) {
  const trimmed = value.trim();
  const parsed = new Date(trimmed);
  if (!trimmed || Number.isNaN(parsed.getTime())) return trimmed || "For the Current Reporting Period";

  return `For the Period Ending ${parsed.toLocaleDateString("en-US", {
    month: "long",
    day: "numeric",
    year: "numeric",
  })}`;
}

function formatReportingPeriodRange(startDate: string, endDate: string) {
  const start = new Date(startDate);
  const end = new Date(endDate);
  if (Number.isNaN(start.getTime()) || Number.isNaN(end.getTime())) {
    return formatPeriodEnding(endDate);
  }

  const formatter = new Intl.DateTimeFormat("en-US", {
    month: "long",
    day: "numeric",
    year: "numeric",
  });

  return `${formatter.format(start)} - ${formatter.format(end)}`;
}

function parseOperationalDate(value: unknown) {
  const text = String(value || "").trim();
  if (!text) return null;
  const parsed = new Date(text);
  return Number.isNaN(parsed.getTime()) ? null : parsed;
}

function formatIsoDate(date: Date | null) {
  return date ? date.toISOString().slice(0, 10) : "";
}

function daysBetween(start: Date, end: Date) {
  const msPerDay = 24 * 60 * 60 * 1000;
  return Math.round((Date.UTC(end.getFullYear(), end.getMonth(), end.getDate()) - Date.UTC(start.getFullYear(), start.getMonth(), start.getDate())) / msPerDay);
}

function addDays(date: Date, days: number) {
  const copy = new Date(date);
  copy.setDate(copy.getDate() + days);
  return copy;
}

function extractDateFromText(value: string) {
  const match = value.match(/\b(\d{1,2}[/-]\d{1,2}[/-]\d{2,4}|20\d{2}-\d{1,2}-\d{1,2})\b/);
  return match ? parseOperationalDate(match[1]) : null;
}

function getQuickBooksReportColumns(report: QuickBooksFetchedReport["data"]) {
  return (
    report?.Columns?.Column?.map((column) => column.ColTitle || column.ColType || "")
      .filter((column) => String(column).trim().length > 0) || []
  );
}

function getQuickBooksRowValues(row: Record<string, unknown>) {
  const colData = Array.isArray(row.ColData) ? row.ColData : [];
  return colData.map((cell) => {
    if (cell && typeof cell === "object" && "value" in cell) {
      return (cell as { value?: unknown }).value ?? "";
    }
    return "";
  });
}

function flattenQuickBooksRows(rows: unknown[] = [], depth = 0): unknown[][] {
  return rows.flatMap((row) => {
    if (!row || typeof row !== "object") return [];
    const typedRow = row as Record<string, unknown>;
    const flattenedRows: unknown[][] = [];

    if (typedRow.Header && typeof typedRow.Header === "object") {
      const values = getQuickBooksRowValues(typedRow.Header as Record<string, unknown>);
      if (values.length) flattenedRows.push([`${"  ".repeat(depth)}${values[0] || ""}`, ...values.slice(1)]);
    }

    const values = getQuickBooksRowValues(typedRow);
    if (values.length) flattenedRows.push([`${"  ".repeat(depth)}${values[0] || ""}`, ...values.slice(1)]);

    const childRows = (typedRow.Rows as { Row?: unknown[] } | undefined)?.Row;
    if (Array.isArray(childRows)) {
      flattenedRows.push(...flattenQuickBooksRows(childRows, depth + 1));
    }

    if (typedRow.Summary && typeof typedRow.Summary === "object") {
      const summaryValues = getQuickBooksRowValues(typedRow.Summary as Record<string, unknown>);
      if (summaryValues.length) {
        flattenedRows.push([`${"  ".repeat(depth)}${summaryValues[0] || "Total"}`, ...summaryValues.slice(1)]);
      }
    }

    return flattenedRows;
  });
}

function quickBooksReportToParsedFile(name: string, report: QuickBooksFetchedReport["data"]): ParsedFile {
  const headerRows = [
    [report?.Header?.ReportName || name],
    [report?.Header?.StartPeriod || "", report?.Header?.EndPeriod || ""].filter(Boolean),
    getQuickBooksReportColumns(report),
  ].filter((row) => row.length > 0);
  const rows = flattenQuickBooksRows(report?.Rows?.Row || []);

  return {
    name: `${name} - QuickBooks Online`,
    rows: [...headerRows, ...rows],
  };
}

/**
 * Fallback-aware wrapper around `formatCurrency`. Renders a human-readable
 * placeholder (default `"Not found"`) when the value is nullish, rather than
 * an empty string. Used in narrative builders where "not found" carries
 * meaning distinct from a zero balance.
 *
 * MC-2d.3a: currency parameter added, defaults to `"USD"`. All existing
 * call sites remain unchanged.
 */
function formatOptionalCurrency(
  value: number | null | undefined,
  fallback: string = "Not found",
  currency: string | null | undefined = DEFAULT_FALLBACK_CURRENCY,
) {
  return value === null || value === undefined ? fallback : formatCurrency(value, currency);
}

function formatNumber(value: number | null | undefined) {
  if (value === null || value === undefined) return "";
  return new Intl.NumberFormat("en-US", { maximumFractionDigits: 0 }).format(value);
}

function formatFte(value: number | null | undefined) {
  if (value === null || value === undefined) return "";
  return new Intl.NumberFormat("en-US", { minimumFractionDigits: 2, maximumFractionDigits: 2 }).format(value);
}

function formatPercent(value: number | null | undefined) {
  if (value === null || value === undefined) return "";
  const percentValue = Math.abs(value) <= 1 ? value * 100 : value;
  const formatted = `${Math.abs(percentValue).toFixed(1)}%`;
  return percentValue < 0 ? `(${formatted})` : formatted;
}

function formatNotMeaningfulPercent(value: number | null | undefined) {
  if (value === null || value === undefined || !Number.isFinite(value)) return "N/M";
  if (Math.abs(value) > 999) return "N/M";
  return `${value.toFixed(1)}%`;
}

function formatFluxPercentLabel(row: FluxRow) {
  if (row.percentVariance === null) {
    if (row.priorAmount === 0 && row.currentAmount !== 0) return "New Activity";
    if (row.priorAmount === 0) return "No Prior Balance";
    return "Not Meaningful";
  }
  const value = isExpenseLikeFluxRow(row) ? Math.abs(row.percentVariance) : row.percentVariance;
  return formatNotMeaningfulPercent(value);
}

function formatRate(value: number | null | undefined) {
  if (value === null || value === undefined) return "";
  return value.toFixed(4).replace(/0+$/, "").replace(/\.$/, "");
}

function escapeXml(value: string | number | null | undefined) {
  return String(value ?? "")
    .replace(/[\u0000-\u0008\u000B\u000C\u000E-\u001F]/g, "")
    .slice(0, 900)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;");
}

function sanitizeFilename(value: string) {
  return value.replace(/[\\/:*?"<>|]/g, "").replace(/\s+/g, " ").trim() || "Advisacor Presentation";
}

function createCrc32Table() {
  const table: number[] = [];
  for (let i = 0; i < 256; i += 1) {
    let crc = i;
    for (let bit = 0; bit < 8; bit += 1) {
      crc = crc & 1 ? 0xedb88320 ^ (crc >>> 1) : crc >>> 1;
    }
    table[i] = crc >>> 0;
  }
  return table;
}

const CRC32_TABLE = createCrc32Table();

function crc32(bytes: Uint8Array) {
  let crc = 0xffffffff;
  bytes.forEach((byte) => {
    crc = CRC32_TABLE[(crc ^ byte) & 0xff] ^ (crc >>> 8);
  });
  return (crc ^ 0xffffffff) >>> 0;
}

function writeUint16(bytes: Uint8Array, offset: number, value: number) {
  bytes[offset] = value & 0xff;
  bytes[offset + 1] = (value >>> 8) & 0xff;
}

function writeUint32(bytes: Uint8Array, offset: number, value: number) {
  bytes[offset] = value & 0xff;
  bytes[offset + 1] = (value >>> 8) & 0xff;
  bytes[offset + 2] = (value >>> 16) & 0xff;
  bytes[offset + 3] = (value >>> 24) & 0xff;
}

function concatBytes(chunks: Uint8Array[]) {
  const totalLength = chunks.reduce((total, chunk) => total + chunk.length, 0);
  const output = new Uint8Array(totalLength);
  let offset = 0;
  chunks.forEach((chunk) => {
    output.set(chunk, offset);
    offset += chunk.length;
  });
  return output;
}

function createZipBlob(files: Array<{ path: string; content: string }>, mimeType: string) {
  const encoder = new TextEncoder();
  const localChunks: Uint8Array[] = [];
  const centralChunks: Uint8Array[] = [];
  let offset = 0;

  files.forEach((file) => {
    const nameBytes = encoder.encode(file.path);
    const data = encoder.encode(file.content);
    const crc = crc32(data);
    const localHeader = new Uint8Array(30 + nameBytes.length);
    writeUint32(localHeader, 0, 0x04034b50);
    writeUint16(localHeader, 4, 20);
    writeUint16(localHeader, 6, 0);
    writeUint16(localHeader, 8, 0);
    writeUint16(localHeader, 10, 0);
    writeUint16(localHeader, 12, 0);
    writeUint32(localHeader, 14, crc);
    writeUint32(localHeader, 18, data.length);
    writeUint32(localHeader, 22, data.length);
    writeUint16(localHeader, 26, nameBytes.length);
    writeUint16(localHeader, 28, 0);
    localHeader.set(nameBytes, 30);
    localChunks.push(localHeader, data);

    const centralHeader = new Uint8Array(46 + nameBytes.length);
    writeUint32(centralHeader, 0, 0x02014b50);
    writeUint16(centralHeader, 4, 20);
    writeUint16(centralHeader, 6, 20);
    writeUint16(centralHeader, 8, 0);
    writeUint16(centralHeader, 10, 0);
    writeUint16(centralHeader, 12, 0);
    writeUint16(centralHeader, 14, 0);
    writeUint32(centralHeader, 16, crc);
    writeUint32(centralHeader, 20, data.length);
    writeUint32(centralHeader, 24, data.length);
    writeUint16(centralHeader, 28, nameBytes.length);
    writeUint16(centralHeader, 30, 0);
    writeUint16(centralHeader, 32, 0);
    writeUint16(centralHeader, 34, 0);
    writeUint16(centralHeader, 36, 0);
    writeUint32(centralHeader, 38, 0);
    writeUint32(centralHeader, 42, offset);
    centralHeader.set(nameBytes, 46);
    centralChunks.push(centralHeader);
    offset += localHeader.length + data.length;
  });

  const centralDirectory = concatBytes(centralChunks);
  const endRecord = new Uint8Array(22);
  writeUint32(endRecord, 0, 0x06054b50);
  writeUint16(endRecord, 4, 0);
  writeUint16(endRecord, 6, 0);
  writeUint16(endRecord, 8, files.length);
  writeUint16(endRecord, 10, files.length);
  writeUint32(endRecord, 12, centralDirectory.length);
  writeUint32(endRecord, 16, offset);
  writeUint16(endRecord, 20, 0);

  return new Blob([concatBytes([...localChunks, centralDirectory, endRecord])], { type: mimeType });
}

function pptParagraph(text: string, size: number, color = "E2E8F0", bold = false) {
  return `<a:p><a:r><a:rPr lang="en-US" sz="${size}"${bold ? ' b="1"' : ""}><a:solidFill><a:srgbClr val="${color}"/></a:solidFill></a:rPr><a:t>${escapeXml(text)}</a:t></a:r></a:p>`;
}

function pptShape({
  id,
  name,
  x,
  y,
  cx,
  cy,
  fill,
  paragraphs,
}: {
  id: number;
  name: string;
  x: number;
  y: number;
  cx: number;
  cy: number;
  fill?: string;
  paragraphs: string;
}) {
  const hasText = Boolean(paragraphs);
  return `
    <p:sp>
      <p:nvSpPr><p:cNvPr id="${id}" name="${escapeXml(name)}"/><p:cNvSpPr${hasText ? ' txBox="1"' : ""}/><p:nvPr/></p:nvSpPr>
      <p:spPr>
        <a:xfrm><a:off x="${x}" y="${y}"/><a:ext cx="${cx}" cy="${cy}"/></a:xfrm>
        <a:prstGeom prst="rect"><a:avLst/></a:prstGeom>
        ${fill ? `<a:solidFill><a:srgbClr val="${fill}"/></a:solidFill>` : "<a:noFill/>"}
        <a:ln><a:noFill/></a:ln>
      </p:spPr>
      ${hasText ? `<p:txBody><a:bodyPr wrap="square" anchor="t"/><a:lstStyle/>${paragraphs}</p:txBody>` : ""}
    </p:sp>
  `;
}

function buildSlideXml(slide: PowerPointSlideData, index: number, slideCount: number, preparedBy: string, homeCurrency: string) {
  let shapeId = 2;
  const nextId = () => shapeId++;
  const maxChartValue = Math.max(
    1,
    ...slide.chartData.slice(0, 6).map((item) => Math.abs(Number(item.value || 0))),
  );
  const bulletParagraphs = (slide.bullets.length ? slide.bullets : ["No data available for this section."])
    .slice(0, 6)
    .map((bullet) => pptParagraph(`- ${bullet}`, 1600, "E2E8F0"))
    .join("");
  const chartShapes = slide.chartData
    .slice(0, 6)
    .map((item, chartIndex) => {
      const value = Number(item.value || 0);
      const y = 2670000 + chartIndex * 440000;
      const barWidth = Math.max(170000, Math.round((Math.abs(value) / maxChartValue) * 2650000));
      return [
        pptShape({
          id: nextId(),
          name: `Chart Label ${chartIndex + 1}`,
          x: 6920000,
          y,
          cx: 1750000,
          cy: 260000,
          paragraphs: pptParagraph(String(item.name || "Metric"), 1150, "CBD5E1", true),
        }),
        pptShape({
          id: nextId(),
          name: `Chart Value ${chartIndex + 1}`,
          x: 8720000,
          y,
          cx: 980000,
          cy: 260000,
          paragraphs: pptParagraph(formatCurrency(value, homeCurrency), 1150, "BFDBFE", true),
        }),
        pptShape({
          id: nextId(),
          name: `Chart Bar ${chartIndex + 1}`,
          x: 9850000,
          y: y + 65000,
          cx: barWidth,
          cy: 120000,
          fill: value < 0 ? "C0845A" : "5B8CFF",
          paragraphs: "",
        }),
      ].join("");
    })
    .join("");

  return `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
    <p:sld xmlns:a="http://schemas.openxmlformats.org/drawingml/2006/main" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships" xmlns:p="http://schemas.openxmlformats.org/presentationml/2006/main">
      <p:cSld>
        <p:bg><p:bgPr><a:solidFill><a:srgbClr val="0B1020"/></a:solidFill><a:effectLst/></p:bgPr></p:bg>
        <p:spTree>
          <p:nvGrpSpPr><p:cNvPr id="1" name=""/><p:cNvGrpSpPr/><p:nvPr/></p:nvGrpSpPr>
          <p:grpSpPr><a:xfrm><a:off x="0" y="0"/><a:ext cx="0" cy="0"/><a:chOff x="0" y="0"/><a:chExt cx="0" cy="0"/></a:xfrm></p:grpSpPr>
          ${pptShape({
            id: nextId(),
            name: "Kicker",
            x: 610000,
            y: 430000,
            cx: 7200000,
            cy: 300000,
            paragraphs: pptParagraph(`SLIDE ${index + 1} / ${slideCount} • ${slide.sectionType}`, 1050, "93C5FD", true),
          })}
          ${pptShape({
            id: nextId(),
            name: "Title",
            x: 610000,
            y: 820000,
            cx: 10400000,
            cy: 780000,
            paragraphs: pptParagraph(slide.title, 3000, "F8FAFC", true),
          })}
          ${pptShape({
            id: nextId(),
            name: "Subtitle",
            x: 610000,
            y: 1570000,
            cx: 9900000,
            cy: 420000,
            paragraphs: pptParagraph(slide.subtitle, 1450, "CBD5E1"),
          })}
          ${pptShape({
            id: nextId(),
            name: "Narrative Card",
            x: 610000,
            y: 2300000,
            cx: slide.chartData.length ? 5600000 : 11100000,
            cy: 3500000,
            fill: "111827",
            paragraphs: bulletParagraphs,
          })}
          ${
            slide.chartData.length
              ? pptShape({
                  id: nextId(),
                  name: "Chart Card",
                  x: 6610000,
                  y: 2300000,
                  cx: 5650000,
                  cy: 3500000,
                  fill: "172033",
                  paragraphs: pptParagraph("Chart Data", 1400, "F8FAFC", true),
                })
              : ""
          }
          ${chartShapes}
          ${pptShape({
            id: nextId(),
            name: "Footer",
            x: 610000,
            y: 6350000,
            cx: 9000000,
            cy: 230000,
            paragraphs: pptParagraph(`Prepared by ${preparedBy || "Advisacor"}`, 900, "94A3B8"),
          })}
        </p:spTree>
      </p:cSld>
      <p:clrMapOvr><a:masterClrMapping/></p:clrMapOvr>
    </p:sld>`;
}

